package ssg
package js
package compress

import CompressTestHelper.{ AllOff, assertCompresses }

final class CompressToplevelAwaitSuite extends munit.FunSuite {

  override val munitTimeout = scala.concurrent.duration.Duration(120, "s")

  // =========================================================================
  // toplevel_await
  // =========================================================================
  test("toplevel_await") {
    assertCompresses(
      input = """'use strict';
        await x""".stripMargin.trim,
      expected = """'use strict';
        await x""".stripMargin.trim,
      options = AllOff
    )
  }

  // =========================================================================
  // toplevel_await_for
  // =========================================================================
  test("toplevel_await_for") {
    assertCompresses(
      input = """'use strict'
        for await (const x of y) {
            foo();
        }""".stripMargin.trim,
      expected = """'use strict'
        for await (const x of y) foo()""".stripMargin.trim,
      options = AllOff
    )
  }

}
